import profileImage from "../assets/main-profile.jpg";
const Profile = () => {
  return (
    <div className="flex flex-col justify-center items-center mt-1 font-fontHead text-black dark:text-white">
      <img
        src={profileImage}
        alt="aziz"
        className="w-[190px] rounded-full mb-1"
        data-aos="flip-left"
        data-aos-duration="2000"
        data-aos-once="true"
      />
      <h1 className="text-lg text-[#f06837]">@avnexcode</h1>
    </div>
  );
};
export default Profile;
